import{_ as e,o as t,c as s,a2 as r}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Arquitectura interna de Spark","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/pyspark/10-arquitectura-interna-de-spark.md","filePath":"data-engineering/pyspark/10-arquitectura-interna-de-spark.md","lastUpdated":1782521464000}'),i={name:"data-engineering/pyspark/10-arquitectura-interna-de-spark.md"};function n(o,a,l,c,d,p){return t(),s("div",null,[...a[0]||(a[0]=[r(`<h1 id="arquitectura-interna-de-spark" tabindex="-1">Arquitectura interna de Spark <a class="header-anchor" href="#arquitectura-interna-de-spark" aria-label="Permalink to &quot;Arquitectura interna de Spark&quot;">​</a></h1><p>Spark distribuye trabajo entre driver y executors. Entender esta arquitectura ayuda a evitar errores de memoria, lentitud y mal uso de <code>collect()</code>.</p><h2 id="componentes" tabindex="-1">Componentes <a class="header-anchor" href="#componentes" aria-label="Permalink to &quot;Componentes&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D[&quot;Driver&quot;] --&gt; CM[&quot;Cluster manager&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  CM --&gt; E1[&quot;Executor 1&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  CM --&gt; E2[&quot;Executor 2&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E1 --&gt; T1[&quot;Tasks&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E2 --&gt; T2[&quot;Tasks&quot;]</span></span></code></pre></div><h2 id="driver" tabindex="-1">Driver <a class="header-anchor" href="#driver" aria-label="Permalink to &quot;Driver&quot;">​</a></h2><p>El driver crea el plan, coordina jobs y recibe resultados de acciones.</p><p>No debe recibir datos enormes con <code>collect()</code>.</p><h2 id="executors" tabindex="-1">Executors <a class="header-anchor" href="#executors" aria-label="Permalink to &quot;Executors&quot;">​</a></h2><p>Ejecutan tasks y guardan datos cacheados.</p><h2 id="jobs-stages-y-tasks" tabindex="-1">Jobs, stages y tasks <a class="header-anchor" href="#jobs-stages-y-tasks" aria-label="Permalink to &quot;Jobs, stages y tasks&quot;">​</a></h2><p>Una accion crea un job. El job se divide en stages. Cada stage contiene tasks.</p><p>Los shuffles separan stages.</p><h2 id="catalyst-y-tungsten" tabindex="-1">Catalyst y Tungsten <a class="header-anchor" href="#catalyst-y-tungsten" aria-label="Permalink to &quot;Catalyst y Tungsten&quot;">​</a></h2><p>Catalyst optimiza planes logicos. Tungsten optimiza ejecucion fisica y memoria.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Evita traer datos grandes al driver.</li><li>Revisa stages en Spark UI.</li><li>Entiende que shuffle separa stages.</li><li>Ajusta recursos segun datos, no por intuicion.</li><li>Prefiere DataFrame API y SQL sobre RDDs para analitica.</li></ul>`,16)])])}const k=e(i,[["render",n]]);export{h as __pageData,k as default};
